+async function withTempRoot<T>(prefix: string, run: (base: string) => Promise<T>): Promise<T> {
+  const base = await fs.mkdtemp(path.join(os.tmpdir(), prefix));
+  try {
+    return await run(base);
+  } finally {
+    await fs.rm(base, { recursive: true, force: true });
+  }
+}
